mapper.insert:

    select seq_crm_oper_log.nextval as id from DUAL

insert into crm_oper_log (
    id, request_url, request_method, request_params, response_result, sql_statements,
    trace_id, operator, operate_time, cost_millis, status, error_msg
) values (
    #{id}, #{requestUrl}, #{requestMethod}, #{requestParams}, #{responseResult}, #{sqlStatements},
    #{traceId}, #{operator}, sysdate, #{costMillis}, #{status}, #{errorMsg}
)

mapper.select:
select to_char(operate_time, 'HH24') as "hour", count(1) as "count"
from crm_oper_log where trunc(operate_time) = trunc(sysdate)
group by to_char(operate_time, 'HH24') order by "hour"

select * from (
     order by id desc
) where rownum <= #{limit}
